import React from 'react';

export default function DrGoodesLogo({ className = '', compact = false }) {
  const rootClass = `inline-flex items-center ${className}`.trim();

  if (compact) {
    return (
      <div className={rootClass} aria-label="D.R.GOODES">
        <div className="inline-flex items-end bg-brand-gold px-2 py-2 shadow-[8px_8px_0_rgba(0,0,0,0.12)]">
          <div className="mr-2 flex flex-col justify-end leading-[0.75] text-brand-ink">
            <span className="font-logo text-[1.9rem] font-black">D.</span>
            <span className="-mt-1 font-logo text-[1.9rem] font-black">R.</span>
          </div>
          <span className="font-logo text-[3.7rem] font-black uppercase leading-[0.8] text-brand-ink sm:text-[4.4rem]">
            GOODES
          </span>
        </div>
      </div>
    );
  }

  return (
    <div className={`${rootClass} flex-col items-start gap-2`} aria-label="D.R.GOODES">
      <div className="inline-flex items-end bg-brand-gold px-3 py-3 shadow-[10px_10px_0_rgba(0,0,0,0.12)]">
        <div className="mr-3 flex flex-col justify-end leading-[0.72] text-brand-ink">
          <span className="font-logo text-[2.7rem] font-black sm:text-[3.1rem]">D.</span>
          <span className="-mt-1 font-logo text-[2.7rem] font-black sm:text-[3.1rem]">R.</span>
        </div>
        <span className="font-logo text-[4.8rem] font-black uppercase leading-[0.82] text-brand-ink sm:text-[5.8rem]">
          GOODES
        </span>
      </div>
      <span className="pl-1 text-[0.68rem] font-semibold uppercase tracking-[0.42em] text-brand-ink/75 sm:text-xs">
        Brick Oven Pizza
      </span>
    </div>
  );
}
